'use strict';

var $SyntaxError = require('es-errors/syntax');
var $TypeError = require('es-errors/type');

var substring = require('./substring');

var isInteger = require('math-intrinsics/isInteger');
var isNaN = require('math-intrinsics/isNaN');



module.exports = function ParseHexOctet(string, position) {
	if (typeof string !== 'string') {
		throw new $TypeError('Assertion failed: `string` must be a String');
	}
	if (!isInteger(position) || position < 0) {
		throw new $TypeError('Assertion failed: `position` must be a nonnegative integer');
	}

	var len = string.length; 
	if ((position + 2) > len) { 
		var error = new $SyntaxError('requested a position on a string that does not contain 2 characters at that position'); 
		return [error]; 
	}
	var hexDigits = substring(string, position, position + 2); 

	var n = +('0x' + hexDigits);
	if (isNaN(n)) {
		return [new $SyntaxError('Invalid hexadecimal characters')];
	}
	return n;

	
};
